const caddieCount=document.getElementById("caddie-count"),addBtn=document.getElementById("addCaddie"),qtyInput=document.getElementById("qty"),minusBtn=document.getElementById("decrease"),plusBtn=document.getElementById("add"),min=1;let maxStock=parseInt(qtyInput.max);function getValue(){return parseInt(qtyInput.value)}function setValue(t){qtyInput.value=t}plusBtn.addEventListener("click",()=>{let t=getValue();t<maxStock&&setValue(t+1)}),minusBtn.addEventListener("click",()=>{let t=getValue();t>1&&setValue(t-1)}),addBtn.addEventListener("click",async()=>{const t=addBtn.dataset.id,e=getValue();try{const n=await fetch("../back/router.php?action=add-caddie",{method:"POST",headers:{"Content-Type":"application/json","X-CSRF-TOKEN":getCsrfToken()},body:JSON.stringify({productId:t,quantity:e})}),a=await n.json();a.success?(showNotification("Ajouté au panier","green"),caddieCount.textContent=a.count):showNotification(a.message,"red")}catch(t){console.error(t)}});